// Add a helper function to verify admin status
export const isUserAdmin = async (): Promise<boolean> => {
  try {
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) {
      console.log('No session found, not admin');
      return false;
    }
    
    // Special case for admin@example.com
    if (session.user.email === 'admin@example.com') {
      console.log('Admin email detected, granting admin access');
      
      // Check if the user already exists in profiles table
      const { data: existingProfile, error: profileError } = await supabase
        .from('profiles')
        .select('role')
        .eq('id', session.user.id)
        .single();
        
      // If profile doesn't exist or doesn't have admin role, update it
      if (profileError || !existingProfile || existingProfile.role !== 'admin') {
        console.log('Updating admin@example.com profile with admin role');
        const { error: upsertError } = await supabase
          .from('profiles')
          .upsert({ 
            id: session.user.id,
            name: 'Admin User',
            email: session.user.email,
            role: 'admin'
          });
          
        if (upsertError) {
          console.error('Error upserting profile:', upsertError);
        } else {
          console.log('Successfully created/updated admin profile');
        }
      }
      
      return true;
    }
    
    // Check user metadata first (fastest)
    if (session.user.user_metadata && session.user.user_metadata.role === 'admin') {
      console.log('Admin role found in user metadata');
      return true;
    }
    
    // If not in metadata, check profiles table
    const { data: profile, error } = await supabase
      .from('profiles')
      .select('role')
      .eq('id', session.user.id)
      .single();
      
    if (error) {
      console.error('Error fetching profile:', error);
      // If profile fetch fails, fall back to email check
      return session.user.email === 'admin@example.com';
    }
    
    const isAdmin = profile?.role === 'admin';
    console.log('Admin status from profile:', isAdmin);
    
    // If not admin yet but email is admin@example.com, update profile
    if (!isAdmin && session.user.email === 'admin@example.com') {
      console.log('Updating admin@example.com to have admin role in profile');
      const { error: updateError } = await supabase
        .from('profiles')
        .update({ role: 'admin' })
        .eq('id', session.user.id);
        
      if (updateError) {
        console.error('Error updating profile:', updateError);
      } else {
        console.log('Successfully updated admin role in profile');
        return true;
      }
    }
    
    return isAdmin;
  } catch (error) {
    console.error('Error checking admin status:', error);
    // On error, special case for admin@example.com as fallback
    const { data: { session } } = await supabase.auth.getSession();
    return session?.user?.email === 'admin@example.com' || false;
  }
};

// Add helper to check storage bucket
export const checkStorageBucket = async (bucketName: string): Promise<boolean> => {
  try {
    const { data, error } = await supabase.storage.getBucket(bucketName);
    if (error) {
      console.error(`Bucket ${bucketName} check failed:`, error);
      
      // Try to create the bucket if it doesn't exist
      if (error.message.includes('does not exist')) {
        console.log(`Attempting to create bucket ${bucketName}`);
        
        // Define the bucket creation options
        const bucketOptions = {
          public: true,
          fileSizeLimit: 10 * 1024 * 1024, // 10MB
          allowedMimeTypes: ['image/*']
        };
        
        // Fix TypeScript error by using the correct type assertion method
        const { data: createData, error: createError } = await supabase.storage.createBucket(
          bucketName, 
          // Use a more specific type cast that works with the Supabase API
          bucketOptions as Record<string, unknown>
        );
        
        if (createError) {
          console.error(`Failed to create bucket ${bucketName}:`, createError);
          return false;
        }
        
        console.log(`Successfully created bucket ${bucketName}`);
        return true;
      }
      
      return false;
    }
    console.log(`Bucket ${bucketName} exists:`, data);
    return !!data;
  } catch (error) {
    console.error(`Error checking bucket ${bucketName}:`, error);
    return false;
  }
};

// Add function to ensure project-images bucket exists
export const ensureProjectImagesBucket = async (): Promise<boolean> => {
  const bucketName = 'project-images';
  try {
    // First check if bucket exists
    const { data: bucketData, error: bucketError } = await supabase.storage.getBucket(bucketName);
    
    // If bucket doesn't exist, try to create it
    if (bucketError && bucketError.message.includes('does not exist')) {
      console.log(`${bucketName} bucket does not exist, creating it...`);
      
      // Define bucket options
      const bucketOptions = {
        public: true,
        fileSizeLimit: 10 * 1024 * 1024, // 10MB
        allowedMimeTypes: ['image/*']
      };
      
      // Fix TypeScript error by using the correct type assertion method
      const { error: createError } = await supabase.storage.createBucket(
        bucketName, 
        // Use a more specific type cast that works with the Supabase API
        bucketOptions as Record<string, unknown>
      );
      
      if (createError) {
        console.error(`Failed to create ${bucketName} bucket:`, createError);
        return false;
      }
      
      console.log(`Successfully created ${bucketName} bucket`);
      
      // Now set up the bucket policy for public access
      const { error: policyError } = await supabase.rpc('create_public_bucket_policy', { 
        bucket_id: bucketName 
      });
      
      if (policyError) {
        console.warn(`Note: Could not set public policy on bucket: ${policyError.message}`);
        // Continue anyway as the bucket was created
      }
      
      return true;
    } else if (bucketError) {
      console.error(`Error checking ${bucketName} bucket:`, bucketError);
      return false;
    }
    
    console.log(`${bucketName} bucket exists:`, bucketData);
    return true;
  } catch (error) {
    console.error(`Error in ensureProjectImagesBucket:`, error);
    return false;
  }
};
